@startuml
class "Subject" as Subject {
  observerCollection
  RegisterObserver(observer)
  UnregisterObserver(observer)
  NotifyObservers()
}

class "Observer" as Observer {
  Notify()
}

class "ConcreteObserverA" as ConcreteObserverA {
  Notify()
}

class "ConcreteObserverB" as ConcreteObserverB {
  Notify()
}

Subject --|> Observer : extends
Observer --|> ConcreteObserverA : extends
Observer --|> ConcreteObserverB : extends

Subject --> Observer : aggregation
@enduml
